<template>
  <div id="app" class="flex container h-screen w-full">
    <div class="flex container h-screen w-full">
      <SideNav />

      <div class="w-full h-full overflow-y-scroll no-scrollbar" v-scroll:bottom="loadMore">
        <!-- Top navigation -->
        <div class="px-5 pt-3 flex items-center">
          <button
            @click="gotoProfile()"
            class="rounded-full p-3 px-4 focus:outline-none hover:bg-lightblue"
          >
            <i class="fas fa-arrow-left text-blue"></i>
          </button>
          <div class="lg:block ml-4">
            <h1 class="text-xl font-bold">{{ profile?.username }}</h1>
            <p class="text-left text-sm leading-tight text-dark">
              @{{ profile?.id }}
            </p>
          </div>
        </div>

        <div class="flex flex-row justify-evenly mt-2">
          <button
            @click="goToFollowers()"
            class="w-1/2 text-dark font-bold border-b-2 px-10 py-4 hover:bg-lightblue"
          >
            Followers
          </button>
          <button
            class="w-1/2 text-dark font-bold border-b-2 border-blue px-10 py-4 hover:bg-lightblue"
          >
            Following
          </button>
        </div>

        <Loader :loading="loading" />
        <div
          v-if="!loading && profiles.length === 0"
          class="flex flex-col items-center justify-center w-full pt-10 px-6 text-center"
        >
          <p class="font-bold text-lg">Not following anyone yet</p>
          <p class="text-sm text-dark">When {{ profile?.username || 'this user' }} follows someone, they'll show up here.</p>
        </div>
        <Users v-if="profiles.length" :users="profiles" :loading="loading" />
      </div>

      <div
        class="hidden md:block w-1/3 z-0 h-full border-l border-lighter px-6 py-2 overflow-y-scroll no-scrollbar relative"
      >
        <SearchBar />
      </div>
    </div>
  </div>
</template>

<script>
import SideNav from "../components/SideNav.vue";
import SearchBar from "../components/SearchBar.vue";
import Users from "../components/Users.vue";
import Loader from "../components/Loader.vue";
import {warpnetService} from "@/service/service";

export default {
  name: "Following",
  components: {
    SideNav,
    SearchBar,
    Users,
    Loader,
  },
  data() {
    return {
      loading: true,
      profile: undefined,
      profiles: [],
    };
  },
  methods: {
    gotoProfile() {
      this.$router.push({
        name: "Profile",
        params: {
          id: this.profile.id,
        },
      });
    },
    goToFollowers() {
      this.$router.push({
        name: "Followers",
        params: {
          id: this.profile.id,
        },
      });
    },
    async loadMore() {
      const followings = await warpnetService.getFollowings({userId:this.profile.id, cursorReset: false})
      for (const id of followings) {
        const u = await warpnetService.getProfile(id, this.profile?.node_id)
        this.profiles.push(u)
      }
    },
  },
  async created() {
    console.log("loading component:", this.$options.name);

    try {
      const profileId = this.$route.params.id;
      this.profile = await warpnetService.getProfile(profileId);

      const followings = await warpnetService.getFollowings({userId:profileId, cursorReset: true})
      for (const id of followings) {
        const u = await warpnetService.getProfile(id, this.profile?.node_id)
        if (!u) {
          continue
        }
        this.profiles.push(u)
        this.loading = false;
      }
    } catch (err) {
      console.error("loading component:", this.$options.name, err)
    } finally {
      this.loading = false;
    }
  },
};
</script>
